340	// while the bond is never touched (standby-only change).
341	func TestHubFailoverIdxReMapsOnExpansionGrowShrink(t *testing.T) {
342		activeLit := mustAP(t, "198.51.100.7:51820")
343		specs := []failoverSpec{
344			nameSpec("early.example.com", 51820), // spec 0: hostname, EMPTY at boot
345			litSpec(t, "198.51.100.7:51820"),     // spec 1: literal → boot-active (flat[0])
346		}
347		hp := []hubHealth{&fakeHealth{telemetry.StateUp}}
348		rem := &recordingRemote{}
349		handshakes := 0
350		clk := &fakeClock{now: time.Unix(1000, 0)}
351		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
352		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 0 {
353			t.Fatalf("boot active = (%d,%v) idx=%d, want (1,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, activeLit)
354		}
355	
356		// Grow the earlier standby spec 0 from [] to two records: active flat idx 0 → 2.
357		h.updateResolution(0, []netip.AddrPort{mustAP(t, "203.0.113.1:51820"), mustAP(t, "203.0.113.2:51820")})
358		if rem.calls != 0 || handshakes != 0 {
359			t.Fatalf("growing a standby spec touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
360		}
361		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 2 {
362			t.Fatalf("after grow: active=(%d,%v) idx=%d, want (1,%v) idx=2", h.activeSpec, h.activeAddr, h.idx, activeLit)
363		}
364	
365		// Shrink the earlier standby spec 0 to one record: active flat idx 2 → 1.
366		h.updateResolution(0, []netip.AddrPort{mustAP(t, "203.0.113.1:51820")})
367		if rem.calls != 0 || handshakes != 0 {
368			t.Fatalf("shrinking a standby spec touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
369		}
370		if h.activeSpec != 1 || h.activeAddr != activeLit || h.idx != 1 {
371			t.Fatalf("after shrink: active=(%d,%v) idx=%d, want (1,%v) idx=1", h.activeSpec, h.activeAddr, h.idx, activeLit)
372		}
373	}
374	
375	// TestPeerNeedsHubFailover is acceptance (5): a single-IP-literal peer warrants NO
376	// controller (byte-for-byte pre-G5), while a peer with any hostname spec OR >= 2 flattened
377	// literals does. This is the exact construction gate startHubFailover applies per peer.
378	func TestPeerNeedsHubFailover(t *testing.T) {
379		lit := func(s string) config.EndpointSpec { return config.EndpointSpec{Addr: mustAP(t, s)} }
380		name := func(h string, p uint16) config.EndpointSpec {
381			return config.EndpointSpec{Host: h, Port: p, IsName: true}
382		}
383	
384		cases := []struct {
385			name string
386			peer config.Peer
387			want bool
388		}{
389			{
390				name: "single IP literal → no controller",
391				peer: config.Peer{
392					Endpoints:     mustEndpoints(t, "203.0.113.1:51820"),
393					EndpointSpecs: []config.EndpointSpec{lit("203.0.113.1:51820")},
394				},
395				want: false,
396			},
397			{
398				name: "two IP literals → controller",
399				peer: config.Peer{
400					Endpoints:     mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820"),
401					EndpointSpecs: []config.EndpointSpec{lit("203.0.113.1:51820"), lit("198.51.100.7:51820")},
402				},
403				want: true,
404			},
405			{
406				name: "single hostname → controller (may re-resolve onto a new IP)",
407				peer: config.Peer{
408					Endpoints:     nil,
409					EndpointSpecs: []config.EndpointSpec{name("hub.example.com", 51820)},
410				},
411				want: true,
412			},
413			{
414				name: "hostname + literal → controller",
415				peer: config.Peer{
416					Endpoints:     mustEndpoints(t, "203.0.113.1:51820"),
417					EndpointSpecs: []config.EndpointSpec{name("hub.example.com", 51820), lit("203.0.113.1:51820")},
418				},
419				want: true,
420			},
421		}
422		for _, tc := range cases {
423			t.Run(tc.name, func(t *testing.T) {
424				if got := peerNeedsHubFailover(tc.peer); got != tc.want {
425					t.Fatalf("peerNeedsHubFailover = %v, want %v", got, tc.want)
426				}
427			})
428		}
429	}
430	
431	// TestHubFailoverBootAdoptsFirstResolution is acceptance (7) + the R70 FIRST-RESOLVE INSTALL PATH:
432	// a hostname-only peer boots with every spec's expansion EMPTY (activeSpec == -1) — check can never
433	// rescue it (a one-record expansion keeps the flattened length at 1, under the total<2 guard), so
434	// the first resolution MUST adopt its head as the active endpoint and INSTALL it on the engine peer
435	// (the install collaborator, NOT SetPeerRemote — SetPeerRemote never populates the engine peer's
436	// endpoint) then re-handshake, arming the settle dwell.
437	func TestHubFailoverBootAdoptsFirstResolution(t *testing.T) {
438		first := mustAP(t, "203.0.113.1:51820")
439		specs := []failoverSpec{
440			nameSpec("hub.example.com", 51820), // sole spec: hostname, EMPTY at boot
441		}
442		hp := []hubHealth{&fakeHealth{telemetry.StateDown}}
443		rem := &recordingRemote{}
444		handshakes := 0
445		clk := &fakeClock{now: time.Unix(1000, 0)}
446		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
447		var installed []netip.AddrPort
448		h.install = func(ap netip.AddrPort) { installed = append(installed, ap) }
449		if h.activeSpec != -1 || h.idx != -1 {
450			t.Fatalf("boot active = (spec %d, idx %d), want (spec -1, idx -1) (all specs empty)", h.activeSpec, h.idx)
451		}
452	
453		// First resolution populates the sole hostname spec: adopt its head, INSTALL on the engine peer.
454		h.updateResolution(0, []netip.AddrPort{first})
455	
456		if len(installed) != 1 || installed[0] != first {
457			t.Fatalf("first resolution engine-endpoint install = %v, want exactly [%v] (R70 install path)", installed, first)
458		}
459		if rem.calls != 0 {
460			t.Fatalf("first resolution used SetPeerRemote %d times, want 0 — boot adoption must INSTALL on the engine peer, not repoint the bind remotes (SetPeerRemote never sets the engine peer endpoint, R70)", rem.calls)
461		}
462		if handshakes != 1 {
463			t.Fatalf("first resolution re-handshakes=%d, want 1", handshakes)
464		}
465		if h.activeSpec != 0 || h.activeAddr != first || h.idx != 0 {
466			t.Fatalf("post-adoption active = (%d,%v) idx=%d, want (0,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, first)
467		}
468		// The dwell is armed at adoption time, not construction time.
469		if !h.lastSwitch.Equal(clk.now) {
470			t.Fatalf("lastSwitch=%v, want %v (armed at adoption)", h.lastSwitch, clk.now)
471		}
472	}
473	
474	// TestHubFailoverRepointResetsSettleDwell is acceptance (8): an active-IP-change repoint
475	// (T73's liveness-loss re-resolution flow) must RE-ARM the settle dwell, so the next
476	// all-down check within the dwell does NOT immediately advance off the just-repointed
477	// endpoint — a second disruptive SetPeerRemote before the new address can prove itself.
478	func TestHubFailoverRepointResetsSettleDwell(t *testing.T) {
479		oldA := mustAP(t, "203.0.113.1:51820")
480		newA := mustAP(t, "203.0.113.2:51820")
481		standby := mustAP(t, "198.51.100.7:51820")
482		specs := []failoverSpec{
483			nameSpec("hub.example.com", 51820, oldA), // spec 0: active hostname
484			litSpec(t, "198.51.100.7:51820"),         // spec 1: literal standby
485		}
486		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
487		rem := &recordingRemote{}
488		handshakes := 0
489		clk := &fakeClock{now: time.Unix(1000, 0)}
490		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
491	
492		// Let the boot dwell fully elapse so, absent a reset, the next all-down check WOULD advance.
493		clk.advance(testSettle + time.Second)
494	
495		// The active spec re-resolves to a new IP under hub loss: repoint (one switch).
496		h.updateResolution(0, []netip.AddrPort{newA})
497		if rem.calls != 1 || rem.last != newA {
498			t.Fatalf("repoint SetPeerRemote=%d last=%v, want 1 and %v", rem.calls, rem.last, newA)
499		}
500	
501		// The repoint re-armed the dwell: a check WITHIN the settle must NOT advance off the
502		// just-repointed endpoint, even though every path still reads DOWN.
503		clk.advance(testSettle - time.Millisecond)
504		h.check()
505		if rem.calls != 1 {
506			t.Fatalf("advanced within the dwell after a repoint: SetPeerRemote=%d, want 1 (no second switch)", rem.calls)
507		}
508		if h.activeSpec != 0 || h.activeAddr != newA {
509			t.Fatalf("active moved off the repointed endpoint within the dwell: (%d,%v), want (0,%v)", h.activeSpec, h.activeAddr, newA)
510		}
511	
512		// Once the dwell elapses relative to the repoint, the controller may advance (to standby).
513		clk.advance(2 * time.Millisecond)
514		h.check()
515		if rem.calls != 2 || rem.last != standby {
516			t.Fatalf("no advance after the dwell elapsed: SetPeerRemote=%d last=%v, want 2 and %v", rem.calls, rem.last, standby)
517		}
518	}
519	
520	// TestHubFailoverCrossSpecDuplicateNoSpuriousReMap is acceptance (6), the R70 case: a
521	// hostname STANDBY spec re-resolving onto the SAME AddrPort as the active spec's own literal
522	// must NOT move the active pointer (spec-scoped identity, not bare value) and must not touch
523	// the bond; a subsequent hub-loss advance then walks the FLATTENED order correctly past the
524	// duplicate rather than being confused by it.
525	func TestHubFailoverCrossSpecDuplicateNoSpuriousReMap(t *testing.T) {
526		dup := mustAP(t, "203.0.113.1:51820")   // shared AddrPort across specs 0 and 1
527		tail := mustAP(t, "198.51.100.7:51820") // spec 2 literal standby
528		specs := []failoverSpec{
529			nameSpec("shadow.example.com", 51820), // spec 0: hostname, EMPTY at boot
530			litSpec(t, "203.0.113.1:51820"),       // spec 1: literal dup → boot-active (flat[0])
531			litSpec(t, "198.51.100.7:51820"),      // spec 2: literal standby
532		}
533		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
534		rem := &recordingRemote{}
535		handshakes := 0
536		clk := &fakeClock{now: time.Unix(1000, 0)}
537		h := newHubFailoverFromSpecs(specs, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
538		if h.activeSpec != 1 || h.activeAddr != dup || h.idx != 0 {
539			t.Fatalf("boot active = (%d,%v) idx=%d, want (1,%v) idx=0", h.activeSpec, h.activeAddr, h.idx, dup)
540		}
541	
542		// The standby hostname (spec 0) re-resolves onto the SAME AddrPort as the active spec-1
543		// literal. A bare-value re-map would rebind the active pointer to spec 0's duplicate at
544		// flat index 0; the spec-scoped identity must keep it on spec 1 (now at flat index 1).
545		h.updateResolution(0, []netip.AddrPort{dup})
546		if rem.calls != 0 || handshakes != 0 {
547			t.Fatalf("cross-spec duplicate re-resolution touched the bond: SetPeerRemote=%d handshakes=%d, want 0,0", rem.calls, handshakes)
548		}
549		if h.activeSpec != 1 || h.activeAddr != dup {
550			t.Fatalf("active pointer spuriously re-mapped to (%d,%v), want (1,%v) (own spec's entry)", h.activeSpec, h.activeAddr, dup)
551		}
552		if h.idx != 1 {
553			t.Fatalf("active flattened idx = %d, want 1 (spec-1 dup, past spec-0's duplicate at 0)", h.idx)
554		}
555	
556		// A subsequent hub-loss advance must walk the flattened order to spec 2's tail literal
557		// at flat index 2 — NOT stall on the duplicate at index 0/1.
558		clk.advance(testSettle + time.Second)
559		h.check()
560		if rem.calls != 1 || rem.last != tail {
561			t.Fatalf("advance after duplicate: SetPeerRemote=%d last=%v, want 1 and %v (flattened order to spec-2 tail)", rem.calls, rem.last, tail)
562		}
563		if h.activeSpec != 2 || h.activeAddr != tail || h.idx != 2 {
564			t.Fatalf("post-advance active = (%d,%v) idx=%d, want (2,%v) idx=2", h.activeSpec, h.activeAddr, h.idx, tail)
565		}
566		if handshakes != 1 {
567			t.Fatalf("advance re-handshakes=%d, want 1", handshakes)
568		}
569	}
570

